class Solution:
    def earliestAndLatest(self, n: int, firstPlayer: int, secondPlayer: int) -> List[int]:
        firstPlayer, secondPlayer = min(firstPlayer, secondPlayer), max(firstPlayer, secondPlayer)
        @lru_cache(None)
        def dfs(n, firstPlayer, secondPlayer):
            if n == 1:
                return [1, 1]
            if firstPlayer == 1 and secondPlayer == n:
                return [1, 1]
            new_n = n // 2 + n % 2
            new_firstPlayer = (firstPlayer + 1) // 2
            new_secondPlayer = (n - secondPlayer + 2) // 2
            earliest = float('inf')
            latest = float('-inf')
            for f in range(new_firstPlayer, new_firstPlayer + 1):
                for s in range(new_secondPlayer - 1, new_secondPlayer + 1):
                    if f == s:
                        continue
                    res = dfs(new_n, min(f, s), max(f, s))
                    earliest = min(earliest, res[0])
                    latest = max(latest, res[1])
            return [earliest + 1, latest + 1]
        return dfs(n, firstPlayer, secondPlayer)

